def bubble_sort_count(arr):
    arr = arr.copy()
    comparisons = 0
    swaps = 0
    n = len(arr)
    for i in range(n):
        for j in range(n - 1 - i):
            comparisons += 1
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
                swaps += 1
    return arr, comparisons, swaps

